const rows = $input.all().map(item => item.json);

if (rows.length === 0) {
  return [{
    json: {
      slackMessage: ':white_check_mark: *Daily Aging Report -- Unpaid Invoices (>30 days)*\n\nNo overdue unpaid invoices found today. All clear!'
    }
  }];
}

const today = DateTime.now().toFormat('yyyy-MM-dd');

const lines = rows.map(r => {
  const amount = Number(r.total_outstanding_usd).toFixed(2);
  const count = r.invoice_count;
  const oldest = r.oldest_invoice_date;
  const dunning = (r.max_dunning_step !== null && r.max_dunning_step !== undefined) ? r.max_dunning_step : 0;
  return '- `' + r.mongo_account_id + '` | $' + amount + ' | ' + count + ' invoice(s) | Oldest: ' + oldest + ' | Dunning step: ' + dunning;
});

const totalUsd = rows.reduce((sum, r) => sum + Number(r.total_outstanding_usd), 0).toFixed(2);

const message = [
  ':rotating_light: *Daily Aging Report -- Unpaid Invoices (>30 days)* | ' + today,
  '',
  'Found *' + rows.length + ' account(s)* with overdue balances. Total outstanding: *$' + totalUsd + '*',
  '',
  lines.join('\n'),
  '',
  '_Run automatically every day at 9:00 UTC_'
].join('\n');

return [{ json: { slackMessage: message } }];
